"""Core definitions for the graphlib library."""


class NodeError(Exception):
    """Raised when a node operation fails."""

    def __init__(self, node_id, message, code=None, cause=None):
        self.node_id = node_id
        self.message = message
        self.code = code
        self.cause = cause
        super().__init__(f"[Node {node_id}] {message}")


def create_node(node_id, label=None, **attrs):
    """Factory function to create a new graph node."""
    if not node_id:
        raise NodeError("<empty>", "node_id is required", code=400)
    return {"id": node_id, "label": label or str(node_id), "attrs": attrs, "edges": []}

