"""Edge management for graph structures."""

from .core import NodeError, create_node


class EdgeManager:
    """Manages edges between graph nodes."""

    def __init__(self):
        self._edges = []
        self._node_index = {}

    def add_edge(self, source_id, target_id, weight=1.0):
        """Add an edge between two nodes."""
        if source_id == target_id:
            raise NodeError(source_id, "Self-loops not allowed", code=400)
        edge = {"source": source_id, "target": target_id, "weight": weight}
        self._edges.append(edge)
        return edge

    def get_neighbors(self, node_id):
        """Get all neighbors of a node."""
        neighbors = []
        for e in self._edges:
            if e["source"] == node_id:
                neighbors.append(e["target"])
            elif e["target"] == node_id:
                neighbors.append(e["source"])
        if not neighbors and node_id not in self._node_index:
            raise NodeError(node_id, "Node not found in graph", code=404)
        return neighbors

    def ensure_node(self, node_id, label=None):
        """Ensure a node exists in the index."""
        if node_id not in self._node_index:
            self._node_index[node_id] = create_node(node_id, label=label)
        return self._node_index[node_id]

    def remove_edge(self, source_id, target_id):
        """Remove an edge between two nodes."""
        before = len(self._edges)
        self._edges = [e for e in self._edges if not (e["source"] == source_id and e["target"] == target_id)]
        if len(self._edges) == before:
            raise NodeError(source_id, f"No edge to {target_id}", code=404)

seed_files.graphlib/path.py:
"""Path finding algorithms for graphs."""

from .core import NodeError, create_node


class PathFinder:
    """Finds paths between nodes in a graph."""

    def __init__(self, edges=None):
        self._adjacency = {}
        if edges:
            for e in edges:
                self._adjacency.setdefault(e["source"], []).append(e["target"])
                self._adjacency.setdefault(e["target"], []).append(e["source"])

    def shortest_path(self, start, end):
        """Find shortest path using BFS."""
        if start not in self._adjacency:
            raise NodeError(start, "Start node not in graph", code=404)
        if end not in self._adjacency:
            raise NodeError(end, "End node not in graph", code=404)
        visited = {start}
        queue = [[start]]
        while queue:
            path = queue.pop(0)
            current = path[-1]
            if current == end:
                return path
            for neighbor in self._adjacency.get(current, []):
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(path + [neighbor])
        return None

    def path_to_node_objects(self, path):
        """Convert a path of IDs to node objects."""
        if path is None:
            return []
        return [create_node(nid, label=f"step_{i}") for i, nid in enumerate(path)]

    def all_paths(self, start, end, max_depth=10):
        """Find all paths up to a maximum depth."""
        if start not in self._adjacency:
            raise NodeError(start, "Start node not in graph", code=404)
        results = []
        stack = [(start, [start])]
        while stack:
            current, path = stack.pop()
            if current == end:
                results.append(path)
                continue
            if len(path) >= max_depth:
                continue
            for neighbor in self._adjacency.get(current, []):
                if neighbor not in path:
                    stack.append((neighbor, path + [neighbor]))
        return results

seed_files.graphlib/search.py:
"""Graph search algorithms."""

from .core import NodeError, create_node


class GraphSearch:
    """Implements various graph search strategies."""

    def __init__(self, adjacency=None):
        self._adjacency = adjacency or {}

    def bfs(self, start):
        """Breadth-first search from a starting node."""
        if start not in self._adjacency:
            raise NodeError(start, "Start node not in graph", code=404)
        visited = []
        queue = [start]
        seen = {start}
        while queue:
            node = queue.pop(0)
            visited.append(node)
            for neighbor in self._adjacency.get(node, []):
                if neighbor not in seen:
                    seen.add(neighbor)
                    queue.append(neighbor)
        return visited

    def dfs(self, start):
        """Depth-first search from a starting node."""
        if start not in self._adjacency:
            raise NodeError(start, "Start node not in graph", code=404)
        visited = []
        stack = [start]
        seen = set()
        while stack:
            node = stack.pop()
            if node not in seen:
                seen.add(node)
                visited.append(node)
                for neighbor in reversed(self._adjacency.get(node, [])):
                    stack.append(neighbor)
        return visited

    def find_node(self, predicate):
        """Find first node matching a predicate."""
        for node_id in self._adjacency:
            node = create_node(node_id)
            if predicate(node):
                return node
        return None

    def reachable_from(self, start):
        """Get all nodes reachable from start."""
        try:
            return set(self.bfs(start))
        except NodeError:
            return set()

