"""Graph traversal utilities."""

from .core import NodeError, create_node


class Traversal:
    """Provides graph traversal operations."""

    def __init__(self, adjacency=None):
        self._adjacency = adjacency or {}

    def topological_sort(self, nodes):
        """Perform topological sort on a DAG."""
        in_degree = {n: 0 for n in nodes}
        for n in nodes:
            for neighbor in self._adjacency.get(n, []):
                if neighbor in in_degree:
                    in_degree[neighbor] += 1
        queue = [n for n in nodes if in_degree[n] == 0]
        result = []
        while queue:
            node = queue.pop(0)
            result.append(node)
            for neighbor in self._adjacency.get(node, []):
                if neighbor in in_degree:
                    in_degree[neighbor] -= 1
                    if in_degree[neighbor] == 0:
                        queue.append(neighbor)
        if len(result) != len(nodes):
            raise NodeError("<cycle>", "Graph contains a cycle", code=400)
        return result

    def walk(self, start, visitor_func):
        """Walk the graph from start, calling visitor on each node."""
        if start not in self._adjacency:
            raise NodeError(start, "Start node not in graph", code=404)
        visited = set()
        stack = [start]
        while stack:
            node_id = stack.pop()
            if node_id not in visited:
                visited.add(node_id)
                node_obj = create_node(node_id, label=f"visited_{node_id}")
                visitor_func(node_obj)
                for neighbor in self._adjacency.get(node_id, []):
                    stack.append(neighbor)
        return len(visited)

    def safe_walk(self, start, visitor_func):
        """Walk with error handling."""
        try:
            return self.walk(start, visitor_func)
        except NodeError:
            return 0

    def leaves(self, nodes):
        """Find leaf nodes (no outgoing edges)."""
        return [n for n in nodes if not self._adjacency.get(n, [])]

