"""Graph layout algorithms."""

from .core import NodeError


class LayoutEngine:
    """Computes spatial layouts for graph visualization."""

    def __init__(self, width=800, height=600):
        self._width = width
        self._height = height
        self._positions = {}

    def circular(self, node_ids):
        """Arrange nodes in a circle."""
        if not node_ids:
            raise NodeError("<empty>", "No nodes to layout", code=400)
        import math
        n = len(node_ids)
        cx, cy = self._width / 2, self._height / 2
        radius = min(cx, cy) * 0.8
        for i, nid in enumerate(node_ids):
            angle = 2 * math.pi * i / n
            self._positions[nid] = (cx + radius * math.cos(angle), cy + radius * math.sin(angle))
        return dict(self._positions)

    def grid(self, node_ids, columns=4):
        """Arrange nodes in a grid."""
        if not node_ids:
            raise NodeError("<empty>", "No nodes to layout", code=400)
        spacing_x = self._width / (columns + 1)
        spacing_y = self._height / ((len(node_ids) // columns) + 2)
        for i, nid in enumerate(node_ids):
            col = i % columns
            row = i // columns
            self._positions[nid] = (spacing_x * (col + 1), spacing_y * (row + 1))
        return dict(self._positions)

    def get_position(self, node_id):
        """Get computed position for a node."""
        if node_id not in self._positions:
            raise NodeError(node_id, "Node has no computed position", code=404)
        return self._positions[node_id]

    def has_layout(self, node_id):
        """Check if node has a computed position."""
        return isinstance(self._positions.get(node_id), tuple)

