"""Graph partitioning algorithms."""

from .core import NodeError, create_node


class Partitioner:
    """Splits graphs into partitions."""

    def __init__(self, adjacency=None):
        self._adjacency = adjacency or {}

    def connected_components(self, node_ids):
        """Find connected components."""
        visited = set()
        components = []
        for nid in node_ids:
            if nid not in visited:
                component = []
                stack = [nid]
                while stack:
                    current = stack.pop()
                    if current not in visited:
                        visited.add(current)
                        component.append(current)
                        for neighbor in self._adjacency.get(current, []):
                            stack.append(neighbor)
                components.append(component)
        return components

    def bisect(self, node_ids):
        """Split node list into two roughly equal partitions."""
        if len(node_ids) < 2:
            raise NodeError("<partition>", "Need at least 2 nodes to bisect", code=400)
        mid = len(node_ids) // 2
        return node_ids[:mid], node_ids[mid:]

    def partition_to_subgraphs(self, partitions):
        """Convert partitions to subgraph node objects."""
        result = []
        for partition in partitions:
            subgraph = [create_node(nid, label=f"part_{nid}") for nid in partition]
            result.append(subgraph)
        return result

    def isolated_nodes(self, node_ids):
        """Find nodes with no edges."""
        isolated = []
        for nid in node_ids:
            if not self._adjacency.get(nid, []):
                isolated.append(nid)
        if not isolated:
            raise NodeError("<partition>", "No isolated nodes found", code=404)
        return isolated

    def safe_bisect(self, node_ids):
        """Bisect with error handling."""
        try:
            return self.bisect(node_ids)
        except NodeError:
            return node_ids, []

seed_files.graphlib/cluster.py:
"""Graph clustering algorithms."""

from .core import NodeError, create_node


class ClusterDetector:
    """Detects clusters in graph structures."""

    def __init__(self, adjacency=None):
        self._adjacency = adjacency or {}
        self._clusters = {}

    def label_propagation(self, node_ids):
        """Simple label propagation clustering."""
        if not node_ids:
            raise NodeError("<cluster>", "No nodes to cluster", code=400)
        labels = {nid: nid for nid in node_ids}
        changed = True
        iterations = 0
        while changed and iterations < 100:
            changed = False
            iterations += 1
            for nid in node_ids:
                neighbors = self._adjacency.get(nid, [])
                if neighbors:
                    neighbor_labels = [labels.get(n, n) for n in neighbors if n in labels]
                    if neighbor_labels:
                        most_common = max(set(neighbor_labels), key=neighbor_labels.count)
                        if labels[nid] != most_common:
                            labels[nid] = most_common
                            changed = True
        self._clusters = {}
        for nid, label in labels.items():
            self._clusters.setdefault(label, []).append(nid)
        return dict(self._clusters)

    def get_cluster(self, cluster_id):
        """Get nodes in a specific cluster."""
        if cluster_id not in self._clusters:
            raise NodeError(cluster_id, "Cluster not found", code=404)
        return self._clusters[cluster_id]

    def cluster_nodes_to_objects(self, cluster_id):
        """Convert cluster members to node objects."""
        try:
            members = self.get_cluster(cluster_id)
        except NodeError:
            return []
        return [create_node(nid, label=f"cluster_{cluster_id}") for nid in members]

seed_files.graphlib/merge.py:
"""Graph merging operations."""

from .core import NodeError, create_node


class GraphMerger:
    """Merges multiple graphs together."""

    def __init__(self):
        self._nodes = {}
        self._edges = []

    def add_graph(self, nodes, edges):
        """Add a graph's nodes and edges to the merger."""
        for n in nodes:
            nid = n["id"] if isinstance(n, dict) else n
            if nid not in self._nodes:
                self._nodes[nid] = n
        for e in edges:
            self._edges.append(e)

    def merge(self):
        """Produce the merged graph."""
        if not self._nodes:
            raise NodeError("<merge>", "Nothing to merge", code=400)
        return {"nodes": list(self._nodes.values()), "edges": list(self._edges)}

    def merge_by_label(self, nodes_a, nodes_b):
        """Merge two node lists, combining nodes with the same label."""
        merged = {}
        for n in nodes_a + nodes_b:
            label = n.get("label", n["id"]) if isinstance(n, dict) else str(n)
            if label not in merged:
                nid = n["id"] if isinstance(n, dict) else n
                merged[label] = create_node(nid, label=label)
        return list(merged.values())

    def conflict_check(self, other_nodes):
        """Check for node ID conflicts."""
        conflicts = []
        for n in other_nodes:
            nid = n["id"] if isinstance(n, dict) else n
            if nid in self._nodes:
                conflicts.append(nid)
        if conflicts:
            raise NodeError(conflicts[0], f"Conflicting node IDs: {conflicts}", code=409)
        return False

seed_files.graphlib/filter.py:
"""Graph filtering operations."""

from .core import NodeError, create_node


class GraphFilter:
    """Filters nodes and edges from a graph."""

    def __init__(self, nodes=None, edges=None):
        self._nodes = nodes or []
        self._edges = edges or []

    def filter_nodes(self, predicate):
        """Filter nodes by a predicate function."""
        return [n for n in self._nodes if predicate(n)]

    def remove_node(self, node_id):
        """Remove a node and its edges."""
        before = len(self._nodes)
        self._nodes = [n for n in self._nodes if (n["id"] if isinstance(n, dict) else n) != node_id]
        if len(self._nodes) == before:
            raise NodeError(node_id, "Node not found for removal", code=404)
        self._edges = [e for e in self._edges if e.get("source") != node_id and e.get("target") != node_id]

    def subgraph(self, node_ids):
        """Extract a subgraph containing only the specified nodes."""
        node_set = set(node_ids)
        filtered_nodes = [n for n in self._nodes if (n["id"] if isinstance(n, dict) else n) in node_set]
        filtered_edges = [e for e in self._edges if e.get("source") in node_set and e.get("target") in node_set]
        return {"nodes": filtered_nodes, "edges": filtered_edges}

    def rebuild_node(self, node_id, **new_attrs):
        """Rebuild a node with updated attributes."""
        for i, n in enumerate(self._nodes):
            nid = n["id"] if isinstance(n, dict) else n
            if nid == node_id:
                self._nodes[i] = create_node(node_id, **new_attrs)
                return self._nodes[i]
        raise NodeError(node_id, "Cannot rebuild: node not found", code=404)

