"""Graph transformation operations."""

from .core import NodeError, create_node


class GraphTransformer:
    """Transforms graph structures."""

    def __init__(self, nodes=None, edges=None):
        self._nodes = {(n["id"] if isinstance(n, dict) else n): n for n in (nodes or [])}
        self._edges = edges or []

    def reverse_edges(self):
        """Reverse all edge directions."""
        return [{"source": e["target"], "target": e["source"], "weight": e.get("weight", 1.0)} for e in self._edges]

    def relabel(self, mapping):
        """Relabel nodes according to a mapping dict."""
        result = []
        for nid, node in self._nodes.items():
            new_id = mapping.get(nid, nid)
            result.append(create_node(new_id, label=f"relabeled_{new_id}"))
        return result

    def contract_edge(self, source_id, target_id):
        """Contract an edge, merging two nodes into one."""
        if source_id not in self._nodes:
            raise NodeError(source_id, "Source node not found", code=404)
        if target_id not in self._nodes:
            raise NodeError(target_id, "Target node not found", code=404)
        merged = create_node(source_id, label=f"merged_{source_id}_{target_id}")
        del self._nodes[target_id]
        self._nodes[source_id] = merged
        self._edges = [
            e for e in self._edges
            if not (e["source"] == source_id and e["target"] == target_id)
        ]
        return merged

