"""Graph serialization and deserialization."""

import json
from .core import NodeError, create_node


class GraphSerializer:
    """Serializes graphs to and from various formats."""

    def to_dict(self, nodes, edges):
        """Serialize a graph to a dictionary."""
        return {
            "nodes": [n if isinstance(n, dict) else {"id": n} for n in nodes],
            "edges": list(edges),
        }

    def from_dict(self, data):
        """Deserialize a graph from a dictionary."""
        if "nodes" not in data:
            raise NodeError("<deserialize>", "Missing 'nodes' key in data", code=400)
        nodes = []
        for raw in data["nodes"]:
            nid = raw.get("id") if isinstance(raw, dict) else raw
            if not nid:
                raise NodeError("<unknown>", "Node missing id", code=400)
            nodes.append(create_node(nid, label=raw.get("label")))
        edges = data.get("edges", [])
        return {"nodes": nodes, "edges": edges}

    def to_json(self, nodes, edges):
        """Serialize a graph to JSON string."""
        return json.dumps(self.to_dict(nodes, edges))

    def from_json(self, json_str):
        """Deserialize a graph from a JSON string."""
        try:
            data = json.loads(json_str)
        except json.JSONDecodeError as e:
            raise NodeError("<json>", f"Invalid JSON: {e}", code=400)
        return self.from_dict(data)

