"""Graph validation utilities."""

from .core import NodeError, create_node


class GraphValidator:
    """Validates graph structures for correctness."""

    def validate_node(self, node):
        """Validate a single node object."""
        if not isinstance(node, dict):
            raise NodeError("<invalid>", "Node must be a dict", code=400)
        if "id" not in node:
            raise NodeError("<missing>", "Node missing 'id' field", code=400)
        return True

    def validate_edges(self, edges, valid_node_ids):
        """Validate that all edges reference valid nodes."""
        node_set = set(valid_node_ids)
        for e in edges:
            if e.get("source") not in node_set:
                raise NodeError(e.get("source"), "Edge references unknown source node", code=400)
            if e.get("target") not in node_set:
                raise NodeError(e.get("target"), "Edge references unknown target node", code=400)
        return True

    def validate_graph(self, nodes, edges):
        """Validate an entire graph structure."""
        for n in nodes:
            self.validate_node(n)
        node_ids = [n["id"] for n in nodes]
        self.validate_edges(edges, node_ids)
        return True

    def repair_node(self, raw_data):
        """Attempt to repair a malformed node."""
        if isinstance(raw_data, str):
            return create_node(raw_data)
        if isinstance(raw_data, dict) and "id" in raw_data:
            return create_node(raw_data["id"], label=raw_data.get("label"), **{k: v for k, v in raw_data.items() if k not in ("id", "label")})
        raise NodeError("<repair>", "Cannot repair: unrecognizable format", code=400)

seed_files.graphlib/optimize.py:
"""Graph optimization algorithms."""

from .core import NodeError


class GraphOptimizer:
    """Optimizes graph structures for performance."""

    def __init__(self, adjacency=None):
        self._adjacency = adjacency or {}

    def remove_redundant_edges(self, edges):
        """Remove duplicate edges."""
        seen = set()
        unique = []
        for e in edges:
            key = (e["source"], e["target"])
            if key not in seen:
                seen.add(key)
                unique.append(e)
        return unique

    def prune_unreachable(self, start, node_ids):
        """Remove nodes not reachable from start."""
        if start not in self._adjacency:
            raise NodeError(start, "Start node not in graph", code=404)
        reachable = set()
        stack = [start]
        while stack:
            current = stack.pop()
            if current not in reachable:
                reachable.add(current)
                for neighbor in self._adjacency.get(current, []):
                    stack.append(neighbor)
        pruned = [nid for nid in node_ids if nid not in reachable]
        return {"kept": list(reachable), "pruned": pruned}

    def compact(self, nodes, edges):
        """Compact graph by removing isolated nodes."""
        referenced = set()
        for e in edges:
            referenced.add(e["source"])
            referenced.add(e["target"])
        kept = []
        removed = []
        for n in nodes:
            nid = n["id"] if isinstance(n, dict) else n
            if nid in referenced:
                kept.append(n)
            else:
                removed.append(n)
        return {"nodes": kept, "edges": edges, "removed": removed}

    def minimum_spanning_edges(self, edges):
        """Select edges forming a minimum spanning tree (simplified greedy)."""
        sorted_edges = sorted(edges, key=lambda e: e.get("weight", 1.0))
        parent = {}
        def find(x):
            while parent.get(x, x) != x:
                x = parent[x]
            return x
        mst = []
        for e in sorted_edges:
            rs, rt = find(e["source"]), find(e["target"])
            if rs != rt:
                parent[rs] = rt
                mst.append(e)
        return mst

    def suggest_optimization(self, node_count, edge_count):
        """Suggest an optimization strategy based on graph size."""
        if edge_count > node_count * 3:
            raise NodeError("<dense>", "Graph too dense for simple optimization", code=400)
        if node_count == 0:
            raise NodeError("<empty>", "Cannot optimize empty graph", code=400)
        return "prune" if edge_count < node_count else "compact"

