"""Graph metrics and statistics."""

from .core import NodeError, create_node


class GraphMetrics:
    """Computes metrics and statistics for graphs."""

    def __init__(self, adjacency=None):
        self._adjacency = adjacency or {}

    def degree(self, node_id):
        """Get the degree of a node."""
        if node_id not in self._adjacency:
            raise NodeError(node_id, "Node not in graph", code=404)
        return len(self._adjacency[node_id])

    def degree_distribution(self, node_ids):
        """Compute degree distribution."""
        dist = {}
        for nid in node_ids:
            d = len(self._adjacency.get(nid, []))
            dist[d] = dist.get(d, 0) + 1
        return dist

    def density(self, node_count, edge_count):
        """Compute graph density."""
        if node_count < 2:
            raise NodeError("<density>", "Need at least 2 nodes", code=400)
        max_edges = node_count * (node_count - 1) / 2
        return edge_count / max_edges

    def hub_nodes(self, node_ids, threshold=3):
        """Find hub nodes (high degree)."""
        hubs = []
        for nid in node_ids:
            if len(self._adjacency.get(nid, [])) >= threshold:
                hubs.append(create_node(nid, label=f"hub_{nid}"))
        return hubs

    def record_error(self, exc):
        """Record an error occurrence for metrics."""
        entry = {"type": type(exc).__name__, "message": str(exc)}
        if isinstance(exc, NodeError):
            entry["node_id"] = exc.node_id
            entry["code"] = exc.code
        return entry

