"""Graph comparison operations."""

from .core import NodeError, create_node


class GraphComparator:
    """Compares two graph structures."""

    def node_diff(self, nodes_a, nodes_b):
        """Find nodes present in A but not in B."""
        ids_a = {(n["id"] if isinstance(n, dict) else n) for n in nodes_a}
        ids_b = {(n["id"] if isinstance(n, dict) else n) for n in nodes_b}
        only_in_a = ids_a - ids_b
        only_in_b = ids_b - ids_a
        return {"only_a": list(only_in_a), "only_b": list(only_in_b)}

    def is_subgraph(self, sub_nodes, sub_edges, super_nodes, super_edges):
        """Check if one graph is a subgraph of another."""
        super_ids = {(n["id"] if isinstance(n, dict) else n) for n in super_nodes}
        for n in sub_nodes:
            nid = n["id"] if isinstance(n, dict) else n
            if nid not in super_ids:
                raise NodeError(nid, "Node not found in supergraph", code=404)
        return True

    def merge_diff(self, nodes_a, nodes_b):
        """Merge two node sets, creating new nodes for differences."""
        ids_a = {(n["id"] if isinstance(n, dict) else n) for n in nodes_a}
        ids_b = {(n["id"] if isinstance(n, dict) else n) for n in nodes_b}
        merged = list(nodes_a)
        for nid in ids_b - ids_a:
            merged.append(create_node(nid, label=f"diff_{nid}"))
        return merged

    def isomorphic_check(self, nodes_a, nodes_b):
        """Simple check if two graphs could be isomorphic (same node count)."""
        if len(nodes_a) != len(nodes_b):
            raise NodeError("<iso>", f"Different sizes: {len(nodes_a)} vs {len(nodes_b)}", code=400)
        return True

