"""Graph visualization helpers."""

from .core import NodeError


class GraphVisualizer:
    """Generates visual representations of graphs."""

    def __init__(self):
        self._styles = {}

    def to_dot(self, nodes, edges, directed=True):
        """Generate DOT format string."""
        if not nodes:
            raise NodeError("<viz>", "No nodes to visualize", code=400)
        arrow = "->" if directed else "--"
        graph_type = "digraph" if directed else "graph"
        lines = [f"{graph_type} G {{"]
        for n in nodes:
            nid = n["id"] if isinstance(n, dict) else n
            label = n.get("label", nid) if isinstance(n, dict) else str(n)
            lines.append(f'  "{nid}" [label="{label}"];')
        for e in edges:
            lines.append(f'  "{e["source"]}" {arrow} "{e["target"]}";')
        lines.append("}")
        return "\n".join(lines)

    def to_adjacency_matrix(self, node_ids, edges):
        """Generate adjacency matrix."""
        if not node_ids:
            raise NodeError("<viz>", "No nodes for matrix", code=400)
        idx = {nid: i for i, nid in enumerate(node_ids)}
        n = len(node_ids)
        matrix = [[0] * n for _ in range(n)]
        for e in edges:
            si, ti = idx.get(e["source"]), idx.get(e["target"])
            if si is not None and ti is not None:
                matrix[si][ti] = e.get("weight", 1)
        return matrix

    def set_node_style(self, node_id, **style):
        """Set visual style for a node."""
        self._styles[node_id] = style

    def get_node_style(self, node_id):
        """Get visual style for a node."""
        if node_id not in self._styles:
            raise NodeError(node_id, "No style defined", code=404)
        return self._styles[node_id]

    def has_style(self, node_id):
        """Check if a node has a visual style."""
        return isinstance(self._styles.get(node_id), dict)

