"""Graph builder pattern implementation."""

from .core import NodeError, create_node


class GraphBuilder:
    """Fluent builder for constructing graphs."""

    def __init__(self):
        self._nodes = {}
        self._edges = []

    def add_node(self, node_id, label=None, **attrs):
        """Add a node to the graph being built."""
        if node_id in self._nodes:
            raise NodeError(node_id, "Duplicate node", code=409)
        self._nodes[node_id] = create_node(node_id, label=label, **attrs)
        return self

    def add_edge(self, source, target, weight=1.0):
        """Add an edge to the graph being built."""
        self._edges.append({"source": source, "target": target, "weight": weight})
        return self

    def add_chain(self, *node_ids):
        """Add a chain of connected nodes."""
        for i, nid in enumerate(node_ids):
            if nid not in self._nodes:
                self._nodes[nid] = create_node(nid)
            if i > 0:
                self._edges.append({"source": node_ids[i - 1], "target": nid, "weight": 1.0})
        return self

    def add_star(self, center_id, *leaf_ids):
        """Add a star topology."""
        if center_id not in self._nodes:
            self._nodes[center_id] = create_node(center_id, label=f"center_{center_id}")
        for lid in leaf_ids:
            if lid not in self._nodes:
                self._nodes[lid] = create_node(lid, label=f"leaf_{lid}")
            self._edges.append({"source": center_id, "target": lid, "weight": 1.0})
        return self

    def build(self):
        """Build and return the graph."""
        return {"nodes": list(self._nodes.values()), "edges": list(self._edges)}

