"""Graph import from external formats."""

from .core import NodeError, create_node


class GraphImporter:
    """Imports graphs from various external formats."""

    def from_edge_list(self, edge_tuples):
        """Import from edge list of (source, target, weight) tuples."""
        nodes = set()
        edges = []
        for t in edge_tuples:
            if len(t) < 2:
                raise NodeError("<import>", "Edge tuple must have at least 2 elements", code=400)
            source, target = t[0], t[1]
            weight = t[2] if len(t) > 2 else 1.0
            nodes.add(source)
            nodes.add(target)
            edges.append({"source": source, "target": target, "weight": weight})
        return {"nodes": [create_node(nid) for nid in nodes], "edges": edges}

    def from_adjacency_dict(self, adj_dict):
        """Import from adjacency dictionary."""
        nodes = set(adj_dict.keys())
        edges = []
        for source, targets in adj_dict.items():
            for target in targets:
                nodes.add(target)
                edges.append({"source": source, "target": target, "weight": 1.0})
        return {"nodes": [create_node(nid) for nid in nodes], "edges": edges}

    def from_csv(self, csv_text):
        """Import from CSV string."""
        lines = csv_text.strip().split("\n")
        if len(lines) < 2:
            raise NodeError("<csv>", "CSV must have header and at least one row", code=400)
        edges = []
        nodes = set()
        for line in lines[1:]:
            parts = line.split(",")
            if len(parts) < 2:
                continue
            source, target = parts[0].strip(), parts[1].strip()
            weight = float(parts[2].strip()) if len(parts) > 2 else 1.0
            nodes.add(source)
            nodes.add(target)
            edges.append({"source": source, "target": target, "weight": weight})
        return {"nodes": [create_node(nid) for nid in nodes], "edges": edges}

