"""Graph query operations."""

from .core import NodeError, create_node


class GraphQuery:
    """Performs queries on graph structures."""

    def __init__(self, nodes=None, edges=None):
        self._nodes = {(n["id"] if isinstance(n, dict) else n): n for n in (nodes or [])}
        self._edges = edges or []

    def find_by_id(self, node_id):
        """Find a node by its ID."""
        if node_id not in self._nodes:
            raise NodeError(node_id, "Node not found", code=404)
        return self._nodes[node_id]

    def find_by_label(self, label):
        """Find nodes matching a label."""
        results = []
        for n in self._nodes.values():
            if isinstance(n, dict) and n.get("label") == label:
                results.append(n)
        return results

    def find_or_create(self, node_id, label=None):
        """Find a node or create it if it doesn't exist."""
        if node_id in self._nodes:
            return self._nodes[node_id]
        node = create_node(node_id, label=label)
        self._nodes[node_id] = node
        return node

    def edges_from(self, node_id):
        """Get all edges originating from a node."""
        if node_id not in self._nodes:
            raise NodeError(node_id, "Node not found", code=404)
        return [e for e in self._edges if e.get("source") == node_id]

    def count_by_attr(self, attr_name, attr_value):
        """Count nodes with a specific attribute value."""
        count = 0
        for n in self._nodes.values():
            if isinstance(n, dict) and n.get("attrs", {}).get(attr_name) == attr_value:
                count += 1
        return count
